  ('generalpolice-94737317-moex-00607', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '有關電器保護裝置，下列敘述何者正確？', '["若負載為電動機，其斷路器的電流不應大於導線安培容量的2倍以上", "進屋線之過電流保護裝置，不得設於接戶開關之負載側", "緊急電源插座之專用迴路，不得設置漏電斷路器", "裝置熔絲為目前最可靠的漏電保護方法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "3eaa6ffe1e08", "answer_pdf_sha1": "faf004e710c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00608', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '建築物發生閃燃（Flashover）現象，下列敘述何者錯誤？', '["延遲建築物火災到達閃燃階段，為最重要的避難對策", "發生閃燃現象時，居室內的人生存機會低", "同種類等面積之裝潢材料中，壁面影響閃燃時間（F.O.T.）最大", "閃燃現象通常發生在建築物火災的成長期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "3eaa6ffe1e08", "answer_pdf_sha1": "faf004e710c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00609', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '有關自然發火之物質，下列敘述何者正確？', '["硝化棉為分解熱蓄積而發火之物質，在缺氧環境下，不會燃燒", "油渣、塗料為氧化熱蓄積而發火之物質", "活性碳為發酵熱蓄積而發火之物質", "乾草堆為吸著熱蓄積而發火之物質"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "3eaa6ffe1e08", "answer_pdf_sha1": "faf004e710c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00610', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '有關沸騰液體膨脹蒸氣爆炸（BLEVE）之事故現象，下列敘述何者錯誤？', '["專指沸騰狀態之液化瓦斯，氣化膨脹而爆炸之現象", "為儲槽內平衡狀態之氣相與液相失控，液相迅速蒸發成氣相形成衝擊蒸氣之情形", "火球是可燃性物質BLEVE之事故現象", "BLEVE事故之特色為破片飛散"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "3eaa6ffe1e08", "answer_pdf_sha1": "faf004e710c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00611', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '鍋爐因為受腐蝕或發生溝狀侵蝕，導致鍋爐破裂，鍋爐內壓力急速回復為大氣壓力，導致爐內之水 激烈氣化，使鍋爐裂縫繼續擴大，其噴出水蒸氣之推進作用使鍋爐體飛向空中。此類爆炸應歸類為：', '["分解爆炸", "機械爆炸", "蒸氣爆炸", "粉塵爆炸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "3eaa6ffe1e08", "answer_pdf_sha1": "faf004e710c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
